// ─────────────────────────────────────────────────────────────────────────────
// 量度層 · Liangdu — 造像量度之格網數據（粉本庫第一層）
// 類型即律（2026-07-04 主人裁 TS 化）：律以類型鎖之於編譯期，以斷言驗之於載入時。
//
// 一切數值出《佛說造像量度經解》（大正藏 T21n1419，清・工布查布譯解），
// 頁碼錨點注於各行；2026-07-03 深度調研三票對抗校驗，逐字核於 CBETA。
// 單位＝自指：以其尊自身指寬為一，格網無量綱（1 指 = 身高 ÷ 該尊格總指數）。
// 畫像（㡧像）之制：「若㡧像，則不加半指」（p.0942a02–14）——面部三庭均分
// 4/4/4，全身百二十指；加半指作百二十五者，胎偶（塑像）之法，本引擎不取。
// 2026-07-03 自 mandala（js/data/ryodo.js）析出入本庫，自此以此卷為正本，
// mandala 候回填改由 vendor 引之。字段名依《造像標準》用漢名。
// 本模塊載入即自誦戒：和數不合即擲——每開壇，即布薩。
// ─────────────────────────────────────────────────────────────────────────────
// 單位鏈（p.0941b26–c05）：二麥一足，四足一指，十二指一搩，倍搩為肘，四肘為尋
export const 單位 = { 麥: 1 / 8, 足: 1 / 4, 指: 1, 搩: 12, 肘: 24, 尋: 96 };
// 如來縱剖 · 自頂而下（p.0941c05–18）
export const 縱剖 = [
    { 段: '肉髻', 指: 4 }, // 「形似積粟覆甌」
    { 段: '頂髮', 指: 4 }, // 肉髻底→髮際
    { 段: '額', 指: 4 }, // 髮際→白毫中
    { 段: '鼻', 指: 4 }, // 白毫→鼻端
    { 段: '頦', 指: 4 }, // 鼻端→頦底（畫像均分三庭）
    { 段: '頸喉', 指: 4 },
    { 段: '喉至心窩', 指: 12 },
    { 段: '心窩至臍', 指: 12 },
    { 段: '臍至陰藏', 指: 12 }, // 陰藏＝全身正中（自頂 60）
    { 段: '胯骨', 指: 4 },
    { 段: '股', 指: 24 },
    { 段: '膝骨', 指: 4 },
    { 段: '脛', 指: 24 },
    { 段: '足踵', 指: 4 },
];
// 如來橫剖 · 自中線向一側（同錨）；兩側合 120＝身高，縱廣相稱，格網自方
export const 橫剖 = [
    { 段: '中至腋', 指: 12 }, // 胸半寬
    { 段: '膊', 指: 20 }, // 上臂
    { 段: '臂', 指: 16 }, // 前臂
    { 段: '手', 指: 12 },
];
// 坐像折算（p.0941c23–0942a01）
export const 坐像 = {
    盤線: 64, // 陰藏（60）下加四指，「平彈絣線」＝盤腿交線
    座面: 68, // 又加四指，「法身之下邊、寶座之上面」→ 坐高 68 指
    膝寬: 52, // 「與其趺坐雙膝外邊相去間闊分長短平等」＝盤線至白毫之距
    踵距: 4, // 「兩踵相離分得四指」
};
// ── 面部量度（T1419 逐項，2026-07-04 親驗於本地經文 參攷-local/T1419-經文；
//    詳 docs/考據/T1419面部量度.md）。座標制同錨點：z 自頂，x 自中線，畫像制不加半指。──
export const 面部 = {
    面縱: 12, // 「面輪竪縱度，帶半十二指」畫像不加半（p.0942a02–03）
    面橫: 12, // 「三分佛面，縱橫逕十二指」（p.0943b29）
    眉: { 前梢x: 0.375, 起z: 12.4375, 長: 4, 中寬: 0.25 },
    // 「比三麥半之處起…各至足半處即兩眉前梢…至後梢長四指」
    // 「眉如初月牙，中高長四指」「中身寬處有二麥」（p.0943a13–17）
    眼: { 中線z: 14, 大眼角x: 1, 小眼角x: 5, 縫: 0.25, 胞闊: 3, 黑珠徑: 1, 瞳徑: 0.2 },
    // 「自白毫而下比至二指…橫量各至一指處為大眼角」「各去四指
    // 處為小眼角」「眼寬只一足，為入定之相，形似長弓」「白黑睛
    // 三分各分得滿指」「黑珠平分五分…中分為眸子」（p.0942c21–p.0943a08）
    鼻: { 準z: 16, 總寬: 2.25, 柱寬: 0.5, 準高: 1.5 },
    // 「鼻寬二指量，準高指半」「鼻柱及兩孔各寬半指，共合鼻身
    // 寬二指一足」（p.0942c11–19）
    口: { 縫z: 17.5, 長: 4, 上唇厚: 1, 下唇厚: 1, 人中闊: 1 / 3 },
    // 「從鼻柱根至閉口處直量一指半」「口長度四指」「上唇長二指
    // …邊角各一指」「下唇長六足」「人中凹槽闊三分指之一」（p.0942b18–c07）
    頦: { 底z: 20, 廣: 4 }, // 「頦之廣分寬裏向十六足即四指」（p.0942b13）
    耳: { 洞門z: 14, 洞門x: 6, 尖z: 12.5, 廣: 2, 垂底z: 19 },
    // 「耳廣有二指，尖等眉中齊」「洞門正對小眼角」「對兩耳洞門處
    // 橫比之…畫像則十二指」「耳葉縱四指半…耳垂長五指」（p.0943a18–b25）
    白毫: { z: 12, 徑: 1 }, // 「印堂白毫地廣帶半一指」「底盤圓滿廣闊一指」（p.0942c23、p.0943a13）
    頸紋: [20.375, 21.625, 23.625], // 「自頷根以下比一足半處作上紋，由是以下一指零一足處作中紋，
    // 由是以下二指處作下紋」（頷根＝頦下際 z20：20+0.375、+1.25、+2；
    // 親驗時正考據代理誤加四指之訛，p.0943c03–06）
};
// 尊格階梯（《續補》p.0947b11–c28、p.0949b24–c03）——搩度 × 12 ＝ 指
export const 搩度 = {
    佛: 10, // 畫像百二十指
    菩薩: 10, // 具德菩薩同十搩
    佛母: 9, // 108，縱＝廣（佛母／度母作十六歲少女相；羅漢獨覺轉輪王同級）
    忿怒: 8, // 「一切威怒像，通作八搩度」（引《戒教王經》）
    矮身: 6, // 72（吉祥王菩薩之類）
};
// 關節錨點：自頂之累計指數——骨架生成器之根
export function 錨點() {
    const m = { 頂: 0 };
    let y = 0;
    for (const { 段, 指 } of 縱剖) {
        y += 指;
        m[段] = y;
    }
    m.白毫 = m.額; // 白毫中＝額段之末（自頂 12）
    m.陰藏 = m.臍至陰藏; // 自頂 60，全身正中
    return m;
}
// 誦戒：格網和數之斷言，破則擲
export function 誦戒() {
    const 縱 = 縱剖.reduce((s, x) => s + x.指, 0);
    const 橫 = 2 * 橫剖.reduce((s, x) => s + x.指, 0);
    if (縱 !== 120)
        throw new Error(`量度破戒：縱剖 ${縱} ≠ 120`);
    if (橫 !== 120)
        throw new Error(`量度破戒：橫剖 ${橫} ≠ 120（縱廣不相稱）`);
    const m = 錨點();
    if (m.陰藏 !== 60)
        throw new Error(`量度破戒：陰藏 ${m.陰藏} 不居身半`);
    if (坐像.盤線 !== m.陰藏 + 4 || 坐像.座面 !== 坐像.盤線 + 4)
        throw new Error('量度破戒：坐像折算有誤');
    if (坐像.膝寬 !== 坐像.盤線 - m.白毫)
        throw new Error('量度破戒：膝寬不等於盤線至白毫之距');
    // 面部之誦（T1419 逐項自洽）
    if (面部.眼.大眼角x + 4 !== 面部.眼.小眼角x)
        throw new Error('量度破戒：大眼角加眼長四指不至小眼角');
    if (面部.耳.洞門x * 2 !== 面部.面橫)
        throw new Error('量度破戒：兩耳洞門距不等面橫十二指');
    if (面部.白毫.z !== m.白毫 || 面部.頦.底z !== m.頦)
        throw new Error('量度破戒：面部錨與縱剖錨不合');
    if (面部.鼻.柱寬 + 0.5 * 2 + 0.375 * 2 !== 面部.鼻.總寬)
        throw new Error('量度破戒：鼻柱孔翼之和不合總寬二指一足');
}
誦戒();
// 舊名之通（mandala 相容）
export { 誦戒 as verify };
